def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[4]
    mod_slide = mod_prs.slides[4]
    orig_shapes = [s for s in orig_slide.shapes if s.has_text_frame]
    mod_shapes = [s for s in mod_slide.shapes if s.has_text_frame]
    # Compare number of shapes
    if len(orig_shapes) != len(mod_shapes):
        return "Number of text shapes changed on slide 5.", 0.0
    # Compare formatting of each paragraph
    diffs = 0
    total = 0
    for orig_shape, mod_shape in zip(orig_shapes, mod_shapes):
        for op, mp in zip(orig_shape.text_frame.paragraphs, mod_shape.text_frame.paragraphs):
            total += 1
            # Check font size, color, bold, italic, alignment
            if op.font and mp.font:
                if op.font.size != mp.font.size or op.font.bold != mp.font.bold or op.font.italic != mp.font.italic or op.alignment != mp.alignment:
                    diffs += 1
    score = 1.0 if total == 0 else 1.0 - (diffs / total)
    if diffs == 0:
        return "No extraneous formatting changes detected on slide 5.", score
    else:
        return f"{diffs} of {total} paragraphs had extraneous formatting changes.", score

def compute_score() -> tuple[str, float]:
    from pptx import Presentation
    orig_prs = Presentation(original_ppt_path)
    mod_prs = Presentation(modified_ppt_path)
    orig_slide = orig_prs.slides[4]
    mod_slide = mod_prs.slides[4]
    orig_texts = []
    mod_texts = []
    for shape in orig_slide.shapes:
        if shape.has_text_frame:
            orig_texts.append("\n".join([p.text.strip() for p in shape.text_frame.paragraphs]))
    for shape in mod_slide.shapes:
        if shape.has_text_frame:
            mod_texts.append("\n".join([p.text.strip() for p in shape.text_frame.paragraphs]))
    # Remove numbering/bulleting for comparison
    import re
    def clean_list_item(text):
        return re.sub(r"^(\d+[.) ]|[•\-–—·*])", "", text).strip()
    orig_clean = ["\n".join([clean_list_item(line) for line in t.split("\n")]) for t in orig_texts]
    mod_clean = ["\n".join([clean_list_item(line) for line in t.split("\n")]) for t in mod_texts]
    unchanged = sum(1 for a, b in zip(orig_clean, mod_clean) if a == b)
    total = max(len(orig_clean), len(mod_clean))
    if unchanged == total:
        return "Text content preserved except list formatting.", 1.0
    else:
        score = unchanged / total if total > 0 else 0.0
        return f"{unchanged} of {total} text blocks unchanged except formatting.", score

